def _run(
    assessment_dir: Path,
    *,
    pythonpath: Path | None = None,
    extra_args: list[str] | None = None,
) -> subprocess.CompletedProcess[str]:
    env = os.environ.copy()
    if pythonpath is not None:
        prev = env.get("PYTHONPATH", "")
        env["PYTHONPATH"] = f"{pythonpath}{os.pathsep}{prev}" if prev else str(pythonpath)
    argv = ["python3", str(SCRIPT_PATH), str(assessment_dir)]
    if extra_args:
        argv.extend(extra_args)
    return subprocess.run(
        argv,
        env=env,
        capture_output=True,
        text=True,
        check=False,
    )


def _load_handoff(assessment_dir: Path) -> dict[str, Any]:
    path = assessment_dir / "memory-writeback.json"
    assert path.exists(), f"missing handoff: {path}"
    return json.loads(path.read_text(encoding="utf-8"))


