def test_fires_with_all_dimensions_in_observations(
    assessment_dir: Path, shim_capture: tuple[Path, Path]
) -> None:
    shim_path, capture_path = shim_capture
    _write_assessment(assessment_dir, _full_assessment())
    result = _run(assessment_dir, pythonpath=shim_path)

    assert result.returncode == 0, f"stderr: {result.stderr}"
    handoff = _load_handoff(assessment_dir)
    assert handoff["status"] == "fired"
    assert handoff["server"] == "memory"
    assert handoff["entity_type"] == "assessment"
    assert handoff["observations_count"] >= 9  # composite + 7 dims + summary

    # Capture from inside the shim.
    captured = json.loads(capture_path.read_text(encoding="utf-8"))
    assert captured["server"] == "memory"
    assert captured["tool"] == "create_entities"
    entities = captured["args"]["entities"]
    assert len(entities) == 1
    entity = entities[0]

    # Stable name suffix uses the timestamp from assessment.json.
    assert entity["name"].endswith("@2026-05-20T07-30-00Z")
    assert entity["name"].startswith("test-assessment@")
    assert entity["entityType"] == "assessment"

    obs = entity["observations"]
    assert "composite=8.50" in obs
    # All 7 dimensions present.
    for dim in (
        "correctness",
        "security",
        "maintainability",
        "performance",
        "testability",
        "simplicity",
        "canon",
    ):
        assert any(o.startswith(f"{dim}=") for o in obs), f"missing dim: {dim}"
    assert any(o.startswith("summary: ") for o in obs)
    assert any(o.startswith("topic: ") for o in obs)


